query:
{
cloudSqlInstances(
   where: {
      engine: { eq: "mysql" }
      cloudProvider: { eq: "gcp" }
      OR: [
        { dbFlags_NONE: { name: { eq: "skip_show_database" } } }
        { dbFlags_SOME: { name: { eq: "skip_show_database" }, value: { eq: "off" } } }
      ]
    }
  ) {
     ...AssetFragment
  }}
